"""matplotlib.backend_managers — tool manager stubs."""

class ToolManager:
    def __init__(self, figure=None):
        self.figure = figure
        self._tools = {}
    def add_tool(self, name, tool, *args, **kwargs): pass
    def remove_tool(self, name): pass
    def get_tool(self, name, warn=True): return self._tools.get(name)
    def trigger_tool(self, name, sender=None, canvasevent=None, data=None): pass
    def toolmanager_connect(self, s, func): return 0
    def toolmanager_disconnect(self, cid): pass
